from Crypto.PublicKey import DSA

def create_private_key_dsa() -> str:
    key = DSA.generate(2048)
    return key.exportKey().decode('utf-8')

from cryptography.hazmat.primitives.asymmetric.dsa import DSAParameters, DSAKey
from cryptography.hazmat.primitives import serialization

def create_private_key_dsa() -> str:
    parameters = DSAParameters.generate(key_size=2048)
    key = DSAKey.generate(parameters)
    return key.private_bytes(
        encoding=serialization.Encoding.PEM,
        format=serialization.PrivateFormat.TraditionalOpenSSL,
        encryption_algorithm=serialization.NoEncryption()
    ).decode('utf-8')

import jwt

def decode_json_web_token(token: str, key: str) -> dict:
    try:
        return jwt.decode(token, key, algorithms=['HS256'])
    except jwt.PyJWTError:
        return {}

import hashlib

def hash_certificate(cert: str) -> str:
    hash_obj = hashlib.sha256()
    hash_obj.update(cert.encode('utf-8'))
    return hash_obj.hexdigest()

